#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[100005]; scanf("%s",s);
        int seen[4]={0};
        seen[0]=1; // prefix 0
        int pref=0; int ok=0;
        for(int i=0;i<N;i++){
            pref += (s[i]=='L'?1:-1);
            pref = ((pref%4)+4)%4;
            int need = (pref+2)%4; // pref - 2 mod 4
            if(seen[need]){ ok=1; break; }
            seen[pref]=1;
        }
        printf(ok?"YES\n":"NO\n");
    }
    return 0;
}

